INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('227ccf87-af10-41ce-b3ca-682f0045d918', '13b4dcc6-8406-4be9-869f-633d9fee7dfc', '不能创建历史的拜访计划和协访计划', 'plac_date>now', 'trigger', 'from django.utils.timezone import utc, localtime,now,make_aware\nimport datetime\nif instance:\n    if instance.record_type.name in (\'weekly_plan_call_plans\',\'weekly_plan_coaching_plans\'):\n        if type(instance.date) == datetime.date:\n            created_date = localtime(instance.date.replace(tzinfo=utc)).date()\n        else:\n            created_date = (make_aware(datetime.datetime.strptime(instance.date, \'%Y-%m-%d\'))).date()\n        if created_date < now().date():\n            message = u\'不允许创建历史的{}\'.format(instance.record_type.label)\n            raise create_validation_trigger_rule_errors(message)\n', '', '0', '1', '2020-08-19 11:08:42', '1', '2020-10-28 08:06:03', 'pre_save', '1', 'custom', 'plac_date_validation', '1');
